<script setup>
//This file is generated by Table2API.
//If you met a bug, please tell me, thanks!
//wrx 20220722

import { onMounted, ref, watch } from 'vue';
import { NButton, NSpace, NMenu, NBreadcrumb, NBreadcrumbItem, NTab, NTabs } from 'naive-ui';
import Theme from '../theme/theme.vue';
import HeaderButtons from '../headerButtons/HeaderButtons.vue';
import Icon_menuToOff from '../icon/Icon_menuToOff.vue';
import Icon_menuToOn from '../icon/Icon_menuToOn.vue';
import LogoButton from '../headerButtons/LogoButton.vue';
import LayoutIndi_Classic from '../layoutIndi/LayoutIndi_Classic.vue';
const pageTitle = ref(''); //页面标题
const menuOptions = ref([]); //菜单数据

const collapsed = ref(false);
const currentMenuKey = ref('');
const menuInstRef = ref(null);

const breadMenus = ref([]); //面包屑的Menu

const tabMenus = ref([]); //Tab的Menu

const inPara = defineProps({
    platformTitle: String,
    menus: Object,
    renderMenuIcon: Function,
    renderMenuLabel: Function,
    menuSelectObj: Object,
});

defineExpose({ DoMenuRefresh }); // 将方法暴露出来

const emit = defineEmits(['menuSelected']);

onMounted(() => {
    menuOptions.value = inPara.menus;
    pageTitle.value = inPara.platformTitle;
    tabMenus.value.push({
        code: 'Home',
        label: '首页',
    });
});

//监控菜单变化
watch(
    () => inPara.menus,
    (val, pre) => {
        menuOptions.value = val;
    },
    { deep: true }
);

//监控标题变化
watch(
    () => inPara.platformTitle,
    (val, pre) => {
        pageTitle.value = val;
    }
);

//刷新菜单
function DoMenuRefresh() {
    if (inPara.menuSelectObj && inPara.menuSelectObj.code && inPara.menuSelectObj.label) {
        if (menuInstRef.value) {
            setTimeout(() => {
                currentMenuKey.value = inPara.menuSelectObj.code;
                menuInstRef.value.showOption(currentMenuKey.value);
                updateBreadMenu(inPara.menuSelectObj);
                addTabMenu(inPara.menuSelectObj);
            }, 1);
        }
    }
}

//通知
function btnBell() {}

//搜索
function btnFind() {}

//选择菜单
function menuSelected(code, pickedVal) {
    window.localStorage.setItem('menu', code);
    emit('menuSelected', code);
    updateBreadMenu(pickedVal);
    addTabMenu(pickedVal);
}

//点击Title
function titleClick() {
    window.localStorage.setItem('menu', 'Home');
    emit('menuSelected', 'Home');
    currentMenuKey.value = 'Home';
    setTimeout(() => {
        updateBreadMenu(inPara.menuSelectObj);
        addTabMenu(inPara.menuSelectObj);
    }, 1);
}

//点击面包屑
function breadClick(key) {
    window.localStorage.setItem('menu', key);
    emit('menuSelected', key);
    currentMenuKey.value = key;
    setTimeout(() => {
        addTabMenu(inPara.menuSelectObj);
    }, 1);
}

//处理点选Tab
function handleUpdateTab(key) {
    window.localStorage.setItem('menu', key);
    currentMenuKey.value = key;
    emit('menuSelected', key);
    setTimeout(() => {
        updateBreadMenu(inPara.menuSelectObj);
    }, 1);
}

//关闭Tab
function handleTabClose(key) {
    emit('menuTabKilled', key);
    let find = tabMenus.value.findIndex((val) => val.code == key);
    tabMenus.value.splice(find, 1);
    if (find > 0) {
        handleUpdateTab(tabMenus.value[find - 1].code);
    } else {
        if (tabMenus.value.length > 0) {
            handleUpdateTab(tabMenus.value[0].code);
        } else {
            titleClick();
        }
    }
}

//根据给定的menu对象，更新面包屑
function updateBreadMenu(pickedVal) {
    breadMenus.value = [];
    if (pickedVal.path) {
        let pathKeys = pickedVal.path.split('/');
        let pathLabels = pickedVal.alias.split('/');
        for (let i = 0; i < pathKeys.length; i++) {
            let elem = {
                label: pathLabels[i],
                code: pathKeys[i],
            };
            breadMenus.value.push(elem);
        }
    }
}

//根据给定的menu对象，增加Tab
function addTabMenu(pickedVal) {
    let finds = tabMenus.value.filter((val) => val.code == pickedVal.code);
    if (finds.length == 0) {
        if (inPara.menuSelectObj.code && inPara.menuSelectObj.label) {
            tabMenus.value.push({
                label: pickedVal.label,
                code: pickedVal.code,
            });
        }
    }
}
</script>
<template>
    <Theme>
        <LayoutIndi_Classic :IsSmall="collapsed">
            <template #logo-title>
                <LogoButton
                    :title="pageTitle"
                    :showTitle="!collapsed"
                    @menuSelected="titleClick"
                ></LogoButton>
            </template>
            <template #menu-area>
                <div class="sideMenu">
                    <!-- :accordion="true" 手风琴-->
                    <n-menu
                        class="menu_container"
                        ref="menuInstRef"
                        key-field="code"
                        v-model:value="currentMenuKey"
                        :collapsed="collapsed"
                        :collapsed-width="74"
                        :collapsed-icon-size="28"
                        :root-indent="28"
                        :indent="22"
                        :options="menuOptions"
                        @update:value="menuSelected"
                        :render-icon="inPara.renderMenuIcon"
                        :render-label="inPara.renderMenuLabel"
                    />
                </div>
            </template>
            <template #header-buttons>
                <NSpace
                    class="navBar-origin"
                    justify="space-between"
                    :align="'center'"
                    :wrap-item="false"
                >
                    <NSpace :align="'center'" :wrap-item="false">
                        <NButton text @click="collapsed = !collapsed">
                            <template #icon>
                                <Icon_menuToOff v-if="!collapsed"></Icon_menuToOff>
                                <Icon_menuToOn v-else></Icon_menuToOn>
                            </template>
                        </NButton>
                        <NBreadcrumb separator=">">
                            <NBreadcrumbItem
                                :clickable="false"
                                @click="breadClick(sMenu.code)"
                                v-for="sMenu in breadMenus"
                            >
                                {{ sMenu.label }}
                            </NBreadcrumbItem>
                        </NBreadcrumb>
                    </NSpace>

                    <HeaderButtons @find="btnFind" @bell="btnBell"></HeaderButtons>
                </NSpace>
            </template>

            <template #header-tabs>
                <!-- <div style="width: 100%; overflow-x: scroll"> -->
                <NTabs
                    class="tabs-bar"
                    :value="currentMenuKey"
                    :closable="true"
                    type="card"
                    tab-style="scroll-x:auto"
                    @update:value="handleUpdateTab"
                    @close="handleTabClose"
                >
                    <NTab v-for="tab in tabMenus" :name="tab.code || ''">
                        {{ tab.label }}
                    </NTab>
                </NTabs>
                <!-- </div> -->
            </template>

            <template #main-content>
                <div id="layoutCard">
                    <slot name="main">内容</slot>
                </div>
            </template>
        </LayoutIndi_Classic>
    </Theme>
</template>
<style></style>
